import json

# Load the complete histological type analysis from our previous calculation
# We already have the hist_stats from previous analysis

# Let's check all histological types and their CDH1 mutation patterns
brca_file = locals()["var_functions.query_db:94"]
cdh1_file = locals()["var_functions.query_db:80"]

with open(brca_file) as f:
    brca = json.load(f)

with open(cdh1_file) as f:
    cdh1 = json.load(f)

cdh1_set = set([p["ParticipantBarcode"] for p in cdh1])

# Extract all BRCA patients (alive and dead) to see full histological distribution
all_brca = []
pattern = r"TCGA-\w+-\w+"

for rec in brca:
    match = re.search(pattern, rec["Patient_description"])
    if match:
        hist_type = rec["histological_type"]
        if hist_type == "None" or hist_type is None:
            hist_type = "Unknown"
        all_brca.append({
            "barcode": match.group(),
            "hist_type": hist_type,
            "alive": "Alive" in rec["Patient_description"]
        })

# Separate analysis for alive vs all patients
alive_stats = {}
all_stats = {}

for patient in all_brca:
    hist = patient["hist_type"]

    # All patients stats
    if hist not in all_stats:
        all_stats[hist] = {"total": 0, "mutated": 0}
    all_stats[hist]["total"] += 1
    if patient["barcode"] in cdh1_set:
        all_stats[hist]["mutated"] += 1

    # Alive patients only
    if patient["alive"]:
        if hist not in alive_stats:
            alive_stats[hist] = {"total": 0, "mutated": 0}
        alive_stats[hist]["total"] += 1
        if patient["barcode"] in cdh1_set:
            alive_stats[hist]["mutated"] += 1

# Calculate percentages
for hist in alive_stats:
    total = alive_stats[hist]["total"]
    mutated = alive_stats[hist]["mutated"]
    alive_stats[hist]["percentage"] = round(mutated / total * 100, 2) if total > 0 else 0

print("\n=== ALIVE BRCA PATIENTS ONLY ===")
sorted_alive = sorted(alive_stats.items(), key=lambda x: x[1]["percentage"], reverse=True)
for hist, data in sorted_alive[:5]:
    print(f"{hist}: {data['percentage']}% ({data['mutated']}/{data['total']})")

print("\n=== ALL BRCA PATIENTS (ALIVE + DEAD) ===")
sorted_all = sorted(all_stats.items(), key=lambda x: x[1]["mutated"], reverse=True)
for hist, data in sorted_all[:5]:
    pct = round(data["mutated"] / data["total"] * 100, 2) if data["total"] > 0 else 0
    print(f"{hist}: {pct}% ({data['mutated']}/{data['total']})")

# Let's see if there are any other histological types with CDH1 mutations
print(f"\nTotal alive patients: {sum(data['total'] for data in alive_stats.values())}")
print(f"Total CDH1 mutations in alive: {sum(data['mutated'] for data in alive_stats.values())}")

result = {
    "alive_all_hists": {hist: {
        "total": data["total"],
        "mutated": data["mutated"],
        "percentage": data["percentage"]
    } for hist, data in sorted_alive},
    "summary": {
        "total_alive": sum(data["total"] for data in alive_stats.values()),
        "total_cdh1_mutated_alive": sum(data["mutated"] for data in alive_stats.values())
    }
}

print("__RESULT__:")
print(json.dumps(result))

